-- Ken's Hardened V2 Fix

local b64_0xlIlI1l = {}
local char_0xIIl1II='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xl1IIlI=1,#char_0xIIl1II do b64_0xlIlI1l[char_0xIIl1II:sub(i_0xl1IIlI,i_0xl1IIlI)] = i_0xl1IIlI - 1 end

function b64_0xlIlI1l.dec_0x1lIII1(d_0xIII11l)
    d_0xIII11l = string.gsub(d_0xIII11l, '[^'..char_0xIIl1II..'=]', '')
    local r_0xl1IIlI = {}
    for i_0xl1IIlI=1, #d_0xIII11l, 4 do
        local c_0xlIlII1 = b64_0xlIlI1l[d_0xIII11l:sub(i_0xl1IIlI,i_0xl1IIlI)] or 0
        local c_0xllI111 = b64_0xlIlI1l[d_0xIII11l:sub(i_0xl1IIlI+1,i_0xl1IIlI+1)] or 0
        local c_0xlllI1l, c_0xIII1ll = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xIII11l:sub(i_0xl1IIlI+2,i_0xl1IIlI+2)
        if ch3 == "=" then has3 = false else c_0xlllI1l = b64_0xlIlI1l[ch3] or 0 end
        local ch4 = d_0xIII11l:sub(i_0xl1IIlI+3,i_0xl1IIlI+3)
        if ch4 == "=" then has4 = false else c_0xIII1ll = b64_0xlIlI1l[ch4] or 0 end
        local b_0xI1IIII = c_0xlIlII1 * (2^18) + c_0xllI111 * (2^12) + c_0xlllI1l * (2^6) + c_0xIII1ll
        local b_0x1llIll = math.floor(b_0xI1IIII / (2^16)) % (2^8)
        local b_0xlIIlII = math.floor(b_0xI1IIII / (2^8)) % (2^8)
        local b_0xIlllIl = b_0xI1IIII % (2^8)
        table.insert(r_0xl1IIlI, string.char(b_0x1llIll))
        if has3 then table.insert(r_0xl1IIlI, string.char(b_0xlIIlII)) end
        if has4 then table.insert(r_0xl1IIlI, string.char(b_0xIlllIl)) end
    end
    return table.concat(r_0xl1IIlI)
end


local function bxor_0xIIlII1(a_0x1IIIII,b_0xI1lIll)
    if bit32 then return bit32.bxor(a_0x1IIIII,b_0xI1lIll) end
    local r_0xllIl11 = 0
    for i_0xIll1ll = 0, 7 do
        local x_0xIIIlII = a_0x1IIIII % 2
        local y_0xl1I1Il = b_0xI1lIll % 2
        if x_0xIIIlII ~= y_0xl1I1Il then r_0xllIl11 = r_0xllIl11 + (2^i_0xIll1ll) end
        a_0x1IIIII = math.floor(a_0x1IIIII / 2)
        b_0xI1lIll = math.floor(b_0xI1lIll / 2)
    end
    return r_0xllIl11
end


local function bxor_str_0xlI1I1l(s_0xI11lIl, k_0x1I1lIl)
    local r_0xIIlII1 = {}
    for i_0xIlllll=1, #s_0xI11lIl do
        local b_0x1IlIII = string.byte(s_0xI11lIl, i_0xIlllll)
        local kb_0xlI1I1I = string.byte(k_0x1I1lIl, (i_0xIlllll-1) % #k_0x1I1lIl + 1)
        r_0xIIlII1[i_0xIlllll] = string.char(bxor_0xIIlII1(b_0x1IlIII, kb_0xlI1I1I))
    end
    return table.concat(r_0xIIlII1)
end


local function getkeys_0x1lIIll()
    local seed = b64_0xlIlI1l.dec_0x1lIII1("eXo2Z2xUeFk=")
    local k1_enc = b64_0xlIlI1l.dec_0x1lIII1("LCsOCDoiDB8=")
    local k2_enc = b64_0xlIlI1l.dec_0x1lIII1("Hy4DDyo/Mx4=")
    return bxor_str_0xlI1I1l(k1_enc, seed), bxor_str_0xlI1I1l(k2_enc, seed)
end


local function cff_0xlII1ll(a_0xI1IllI)
    local st_0xIIIlI1 = 0
    local res_0xIIIllI = a_0xI1IllI
    while true do
        if st_0xIIIlI1 == 0 then
            res_0xIIIllI = res_0xIIIllI + 1
            st_0xIIIlI1 = 1
        elseif st_0xIIIlI1 == 1 then
            res_0xIIIllI = res_0xIIIllI * 2
            st_0xIIIlI1 = 2
        elseif st_0xIIIlI1 == 2 then
            res_0xIIIllI = res_0xIIIllI - 3
            st_0xIIIlI1 = 3
        else
            break
        end
    end
    return res_0xIIIllI
end


local function chain_0x111lII(x) return x*2 end
local function chain_0x1l11ll(x) return chain_0x111lII(x)+1 end


local d_0xlIIlll = {
  {op=255, val="", is_enc=true},
}
local pc_0xI1IllI = 1
local stk_0x1lllII = {}
stk_0x1lllII._jmp = nil


local disp_0xIllIlI = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0x1lIIll()

local state_0xlI11II = 0
while true do
    if state_0xlI11II == 0 then  -- FETCH
        if pc_0xI1IllI > #d_0xlIIlll then break end
        local inst = d_0xlIIlll[pc_0xI1IllI]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xlIlI1l.dec_0x1lIII1(val)
            d = bxor_str_0xlI1I1l(d, k2)
            val = bxor_str_0xlI1I1l(d, k1)
        end
        stk_0x1lllII._jmp = nil
        pc_0xI1IllI = pc_0xI1IllI + 1
        cur_op_0xIIII1I = opcode
        cur_val_0xIIlllI = val
        state_0xlI11II = 1

    elseif state_0xlI11II == 1 then  -- EXECUTE
        local handler = disp_0xIllIlI[cur_op_0xIIII1I]
        if handler then
            handler(stk_0x1lllII, cur_val_0xIIlllI)
        end
        if stk_0x1lllII._jmp then
            pc_0xI1IllI = pc_0xI1IllI + stk_0x1lllII._jmp
        end
        state_0xlI11II = 0
    else
        break
    end
end
